import sys

def caesar_cipher(message, shift, decode=False):
    if decode:
        shift = -shift

    result = []
    for char in message:
        if char.isalpha():
            if char.isupper():
                shifted = chr((ord(char) - ord('A') + shift) % 26 + ord('A'))
            else:
                shifted = chr((ord(char) - ord('a') + shift) % 26 + ord('a'))
            result.append(shifted)
        else:
            result.append(char)

    return ''.join(result)

